export function trigToDeg(expr: string): string {
  if (/\b(deg|rad)\b/i.test(expr) || /\bpi\b/i.test(expr)) return expr;
  return expr.replace(/\b(sin|cos|tan|asin|acos|atan)\s*\(([^)]+)\)/gi, (_, fn, arg) => {
