  /del\s+\/[sf]/i,
  /rmdir\s+\/s/i,
  /chmod\s+777/i,
  /sudo\s+/i,
  /\|\s*sh\b/i,
  /curl.*\|\s*bash/i,
];

const MEDIUM_PATTERNS = [
  /rm\s+\S+/i,
  /del\s+\S+/i,
  /move\s+/i,
  /mv\s+.*\//i,
  /npm\s+install/i,
  /pip\s+install/i,
  /apt\s+install/i,
];

